#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    long long a[n], prefix[n + 1] = {0};
    for (int i = 0; i < n; i++) {
        scanf("%lld", &a[i]);
    }
    for (int i = n - 1; i >= 0; i--) {
        prefix[i] = prefix[i + 1] + a[i];
    }
    for (int i = 0; i < m; i++) {
        long long x;
        scanf("%lld", &x);
        long long ans = 0;
        for (int j = 0; j < n; j++) {
            long long temp = x / (prefix[j + 1] + 1);
            ans += temp;
            x -= temp * (prefix[j + 1] + 1);
        }
        printf("%lld\n", ans + x);
    }
    return 0;
}

